#!/bin/bash
# solve.sh — oracle golden solution (self-contained, no /tests/ dependency)
# SVG stored as base64 to avoid quoting issues
mkdir -p /task
python3 -c "
import base64
data = ''
svg = base64.b64decode(data).decode()
with open('/task/annotation.svg', 'w') as f:
    f.write(svg)
print('solve.sh: wrote golden annotation.svg to /task/annotation.svg')
"
